function ChessBoard() {
  const [selected, setSelected] = React.useState(null);
  const [moves, setMoves] = React.useState([]);
  const files = ['a','b','c','d','e','f','g','h'];
  const ranks = ['8','7','6','5','4','3','2','1'];

  const handleClick = (sq) => {
    if (selected) {
    if (selected !== sq) {
        setMoves([...moves, `${selected}-${sq}`]);
      }
      setSelected(null);
    } else {
      setSelected(sq);
    }
  };

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 12, background: '#f8fafc', borderRadius: 12, height: '100%', display: 'flex', flexDirection: 'column', color: '#1e293b' }}>
      <h2 style={{ margin: '0 0 8px', fontSize: 16 }}>Chess Board</h2>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(8, 1fr)', gap: 1, background: '#475569', borderRadius: 4, overflow: 'hidden', marginBottom: 8 }}>
        {ranks.map((r) =>
          files.map((f) => {
            const sq = f + r;
            const isDark = (files.indexOf(f) + ranks.indexOf(r)) % 2 === 1;
            const isSel = selected === sq;
            return (
              <button
                key={sq}
                onClick={() => handleClick(sq)}
                style={{
                  aspectRatio: '1',
                  border: 'none',
                  background: isSel ? '#2563eb' : isDark ? '#475569' : '#e2e8f0',
                  color: isSel ? '#fff' : isDark ? '#e2e8f0' : '#475569',
                  fontSize: 10,
                  fontWeight: 600,
                  cursor: 'pointer'
                }}
              >
                {sq}
              </button>
            );
          })
        )}
      </div>
      <div style={{ flex: 1, overflow: 'auto', background: '#fff', borderRadius: 6, padding: 8, fontSize: 12 }}>
        {moves.length === 0 && <span style={{ color: '#94a3b8' }}>No moves yet.</span>}
        {moves.map((m, i) => (
          <div key={i} style={{ padding: '2px 0' }}>
            {Math.floor(i / 2) + 1}. {m}
          </div>
        ))}
      </div>
    </div>
  );
}
render(<ChessBoard/>);
